func (p *ProviderBuilder) BuildProviders() []*Provider {
	if len(p.Namespaces) == 0 {
		return []*Provider{{
			Provider:	p.Provider,
			name:		providerName,
			token:		p.Token,
			tls:		p.TLS,
		}}
	}

	var providers []*Provider
	for _, namespace := range p.Namespaces {
		providers = append(providers, &Provider{
			Provider:	p.Provider,
			name:		providerName + "-" + namespace,
			namespace:	namespace,
			token:		p.Token,
			tls:		p.TLS,
		})
	}

	return providers
}
